member.example:
Bind a relay command to a Toggle's value change using a serialized binder field — the target is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ToggleCommandBinder _onAccepted;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void OnAccepted() { }
        
        [RelayCommand]
        private void OnAccepted(bool isOn) { }
    }


Bind a relay command to a Toggle's value change by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Toggle _target;
        
        private ToggleCommandBinder AcceptedCommand => new(_target);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void OnAccepted(bool isOn) { }
    }

