Bind a relay command with one additional parameter using a MonoBinder component.
Because ToggleCommandMonoBinder<T> is abstract, a concrete derived class is required.

    [AddComponentMenu("MyGame/Binders/AcceptedCommandBinder")]
    public sealed class AcceptedCommandMonoBinder : ToggleCommandMonoBinder<string> { }
    
    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AcceptedCommandMonoBinder _onAccepted;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void OnAccepted(bool isOn, string source) { }
    }

